const explorers = cluster.getAgentsByRole('explorer');
const results = ledger.query({ topic: 'FINDINGS_READY' });
const explorerIds = new Set(explorers.map(e => e.id));
const received = new Set();
for (const msg of results) {
  if (explorerIds.has(msg.sender)) received.add(msg.sender);
}
return received.size >= explorers.length;

const lastVerification = ledger.findLast({ topic: 'VERIFICATION_RESULT', sender: 'verifier-alpha' });
if (!lastVerification) return false;
const newFindings = ledger.query({ topic: 'FINDINGS_READY', since: lastVerification.timestamp });
return newFindings.length > 0;

const explorers = cluster.getAgentsByRole('explorer');
const results = ledger.query({ topic: 'FINDINGS_READY' });
const explorerIds = new Set(explorers.map(e => e.id));
const received = new Set();
for (const msg of results) {
  if (explorerIds.has(msg.sender)) received.add(msg.sender);
}
return received.size >= explorers.length;

const lastVerification = ledger.findLast({ topic: 'VERIFICATION_RESULT', sender: 'verifier-beta' });
if (!lastVerification) return false;
const newFindings = ledger.query({ topic: 'FINDINGS_READY', since: lastVerification.timestamp });
return newFindings.length > 0;

const verifiers = cluster.getAgentsByRole('verifier');
const results = ledger.query({ topic: 'VERIFICATION_RESULT' });
const verifierIds = new Set(verifiers.map(v => v.id));
const received = new Set();
for (const msg of results) {
  if (verifierIds.has(msg.sender)) received.add(msg.sender);
}
if (received.size < verifiers.length) return false;
const latestByVerifier = new Map();
for (const msg of results) {
  if (!verifierIds.has(msg.sender)) continue;
  const existing = latestByVerifier.get(msg.sender);
  if (!existing || msg.timestamp > existing.timestamp) {
    latestByVerifier.set(msg.sender, msg);
  }
}
const explorers = cluster.getAgentsByRole('explorer');
const latestVerificationTime = Math.max(...[...latestByVerifier.values()].map(m => m.timestamp));
const newFindings = ledger.query({ topic: 'FINDINGS_READY', since: latestVerificationTime });
const explorerIds = new Set(explorers.map(e => e.id));
const newExplorerFindings = newFindings.filter(m => explorerIds.has(m.sender));
if (newExplorerFindings.length > 0) return false;
return true;
